#include <bits/stdc++.h>
using namespace std;
long long d[10000002];
bool c[10000002];
int main(){
    long long a,b,x;
    cin>>a>>b;
    for(int i=ceil(sqrt(a));i<=1001;i++){
		for(int j=i*i;j<=10000001;j+=i*i){
			c[j]=1;
		}
	}
	for(int i=10000001;i>=1;i--){
		if (c[i]==1){
			d[i]=i;
		}
		else d[i]=d[i+1];
	}
    for(int i=0;i<b;i++){
        cin>>x;
        if(d[x]==x){
            cout<<"lucky";
        }
        else{
            cout<<d[x];
        }
        cout<<endl;
    }
    return 0;
}
